# Fix "FoodName_Translated" and "FoodName_Recoded" for "makoba" fish
fix_makoba <- function(diet_df) {
  diet_df <- diet_df %>%
    dplyr::mutate(
      FoodName_Translated = case_when(
      FoodName_Recoded == "makoba" ~ "ray",
      .default = FoodName_Translated), 
      FoodName_Recoded = case_when(
        FoodName_Recoded == "makoba" ~ "fay",
        .default = FoodName_Recoded))
  return(diet_df)
}

