# Fill in fish NA gram weights using fish encyclopedia
fix_fish <- function(diet_df, fish_enc_g) {
  fish_enc_g$grams_source <- "fish_enc"
  diet_df <- diet_df %>% 
    # Fill in NA gram weights using fish encyclopedia CPUE weight by name
    rows_patch(fish_enc_g %>% 
                 select(`fish_name`, `grams_per_unit`, grams_source) %>%
                 rename(FoodName_Recoded = fish_name) %>%
                 unique(), 
               by = "FoodName_Recoded", unmatched = "ignore") %>%
    # Fill in NA gram weights using fish encyclopedia CPUE weight by FISHID
    rows_patch(fish_enc_g %>% 
                 select(`FISHID`, `grams_per_unit`, grams_source) %>%
                 drop_na(grams_per_unit) %>% 
                 distinct() %>% 
                 group_by(`FISHID`) %>% 
                 filter(row_number() == 1), 
               by = "FISHID", unmatched = "ignore") %>% 
    # Fill in NA gram weights using fish encyclopedia FB/SLB weight by name
    rows_patch(fish_enc_g %>% 
                 select(`fish_name`, `grams_per_unit_FBSL`, grams_source) %>%
                 rename(FoodName_Recoded = fish_name,
                        grams_per_unit = grams_per_unit_FBSL)%>%
                 drop_na(grams_per_unit) %>% 
                 distinct() %>% 
                 group_by(`FoodName_Recoded`) %>% 
                 filter(row_number() == 1), 
               by = "FoodName_Recoded", unmatched = "ignore") %>%
    # Fill in NA gram weights using fish encyclopedia FB/SLB weight by FISHID
    rows_patch(fish_enc_g %>% 
                 select(`FISHID`, `grams_per_unit_FBSL`, grams_source) %>%
                 rename(grams_per_unit = grams_per_unit_FBSL) %>%
                 select(`FISHID`, grams_per_unit, grams_source)%>%
                 drop_na(grams_per_unit) %>% 
                 distinct() %>% 
                 group_by(`FISHID`) %>% 
                 filter(row_number() == 1), 
               by = "FISHID", unmatched = "ignore")
  return(diet_df)
}

# Fill in NA gram weights using MAHERY average meal weights
# 'mah_foods_avg' is from 'mah_foods_avg.csv'
fix_mah <- function(diet_df, mah_foods_avg) {
  mah_foods_avg$grams_source <- "mah_avg"
  diet_df <- diet_df %>% 
    # Fill in NA gram weights using Mahery averages by Mahery name
    rows_patch(mah_foods_avg %>% 
                 drop_na(dar_name) %>%
                 select(`Malagasy Name`, avg_wt_meal, grams_source) %>%
                 rename(FoodName_Recoded = `Malagasy Name`,
                        grams_per_unit = avg_wt_meal) %>%
                 unique(), 
               by = "FoodName_Recoded", unmatched = "ignore") %>%
    # Fill in NA gram weights using Mahery averages by Darwin name
    rows_patch(mah_foods_avg %>% 
                 drop_na(dar_name) %>%
                 select(dar_name, avg_wt_meal, grams_source) %>%
                 rename(FoodName_Recoded = dar_name,
                        grams_per_unit = avg_wt_meal) %>%
                 unique(), 
               by = "FoodName_Recoded", unmatched = "ignore") %>%
  return(diet_df)
}

# Match missing weight of items to known weight of other item. Called by 
# fix_match() function
# 'miss_items' can be a string vector but 'known_item' must be a string
match_item <- function(diet_df, miss_items, known_item) {
  # Obtain first entry with known weight
  known_weight <- diet_df$grams_per_unit[diet_df$FoodName_Recoded == known_item][1]
  # For each of the missing items, fill in using known weight
  for (i in 1:length(miss_items)) {
    miss_inds <- which(diet_df$FoodName_Recoded == miss_items[i] & 
                       is.na(diet_df$grams_per_unit))
    diet_df[miss_inds, "grams_per_unit"] <- known_weight
    diet_df[miss_inds, "grams_source"] <- paste0("matched_", known_item)
  }
  return(diet_df)
}

# Match missing weight of items to known weights of other items
fix_match <- function(diet_df) {
  diet_df <- match_item(diet_df = diet_df, 
                          miss_items = c("akoho vohitry", "akoho vositry"),
