  diet_df <- match_item(diet_df = diet_df, 
                        miss_items = c("orge", "avoine", "ble"),
                        known_item = "vary")
  diet_df <- match_item(diet_df = diet_df, 
                        miss_items = "sardine",
                        known_item = "sardines")
  diet_df <- match_item(diet_df = diet_df, 
                        miss_items = "sokiny",
