  return(diet_df)
}


# `get_match` returns the matching gram amount for a given unit 
# Inputs:
#   df_hh_i: Row i of household consumption dataframe 
#   df_unit: Dataframe of grams per unit for a category of units
#   ind_hh: Indices of household consumption dataframe to find matching grams 
# per unit
#   ind_unit: Indices of unit dataframe to find matching grams per unit
# Outputs: `grams_per_unit` numeric grams per unit for the given row i unit
get_match <- function(df_hh_i, df_unit, ind_hh, ind_unit) {
  match <- grams_per_unit <- NA
  for (j in 1:nrow(df_unit)) {
    if (!is.character(all.equal(df_unit[j, ind_unit], df_hh_i[ind_hh],
                                check.attributes = FALSE))) {
      match <- j
      break
    }
  }
  if (!is.na(match)) {
    grams_per_unit <- as.numeric(df_unit$Grams.per.unit[match])
  }
  return(grams_per_unit)
}

